sql:
SELECT 
    (SELECT COUNT(*) FROM shareholders WHERE company_id = '1') AS shareholder_count,
    (SELECT COUNT(*) FROM directors WHERE company_id = '1') AS director_count;

external_knowledge:
- "captains" refers to individuals with the role of directors;
- "ship stewards" refer to individuals with the role of shareholders;
- "vessel that has come to rest on the shores of the market" metaphorically refers to closed companies.

sql:
SELECT DISTINCT i.name
FROM individuals i
JOIN (
  SELECT individual_id FROM directors
  UNION
  SELECT individual_id FROM legal_representatives
) AS dr ON i.individual_id = dr.individual_id
WHERE dr.individual_id NOT IN (
  SELECT individual_id FROM judicial_representatives
);

SELECT * 
FROM companies 
WHERE company_id = '0';

SELECT i.individual_id, i.name
FROM individuals i
INNER JOIN directors d ON i.individual_id = d.individual_id;

external_knowledge:
- 'significant investors' refers to individuals holding shares in companies that were registered after the year 2015;
- The term 'newer companies' implies companies that have been registered in the past years, particularly after 2015 for this context;
- The query aims to identify individuals who are shareholders in these newer companies and the total shares they hold across all such companies.

sql:
SELECT i.name
FROM individuals i
INNER JOIN legal_representatives lr ON i.individual_id = lr.individual_id;
